function DrawProgress() {
  const { RingProgress } = components;
  const measureField = "measure_column";
  const targetField = "target_column";
  const total = data.reduce((sum, row) => sum + (row[measureField] || 0), 0);
  const target = data[0]?.[targetField] ?? total;
  const percent = target > 0 ? total / target : 0;
  const config = {
    percent,
    color: ["#5B8FF9", "#E8EDF3"],
    statistic: {
      content: {
        style: { fontSize: 14 },
        content: `${(percent * 100).toFixed(2)}%`
      }
    }
  };
  return <div><RingProgress {...config} /></div>;
}
